arguments.command:
cd /app && python3 -c "
import torch
sd=torch.load('weights.pt')
ks=list(sd.keys())
import re
# count encoder/decoder layers
enc=set(); dec=set()
for k in ks:
    m=re.match(r'transformer_encoder.layers.(\d+)',k)
    if m: enc.add(int(m.group(1)))
    m=re.match(r'transformer_decoder.layers.(\d+)',k)
    if m: dec.add(int(m.group(1)))
print('enc layers',sorted(enc))
print('dec layers',sorted(dec))
print('---decoder keys layer0---')
for k in ks:
    if 'transformer_decoder.layers.0' in k: print(k, tuple(sd[k].shape))
print('--- non-layer keys ---')
for k in ks:
    if '.layers.' not in k: print(k, tuple(sd[k].shape), sd[k].dtype)
" 2>/dev/null

